  const minutes = String(isoDate.getMinutes()).padStart(2, '0');

  return {
    full_date: `${day}/${month}/${year}`,
    full_time: `${hours}:${minutes}`,
    vietnam_format: `${hours}:${minutes} - ${day}/${month}/${year}`
  };
}

// Trả về null nếu không tìm thấy ngày
