const msg = $json.message;
if (!msg) return [];

let type = 'other';
let Topic = msg.reply_to_message?.forum_topic_created?.name || '';
let file_id = null;
let caption = '';
let entities = [];

// photo
if (msg.photo?.length) {
  type = 'photo';
  file_id = msg.photo[msg.photo.length - 1].file_id;
  caption = msg.caption || '';
  entities = msg.caption_entities || [];
}
// video
else if (msg.video) {
  type = 'video';
  file_id = msg.video.file_id;
  caption = msg.caption || '';
  entities = msg.caption_entities || [];
}
// text
else if (msg.text) {
  type = 'text';
  caption = msg.text || '';
  entities = msg.entities || [];
}
// document nếu sau này cần
else if (msg.document) {
  type = 'document';
  file_id = msg.document.file_id;
  caption = msg.caption || '';
  entities = msg.caption_entities || [];
}
// loại khác thì vẫn lưu, caption rỗng
else {
  type = 'other';
  caption = '';
  entities = msg.caption_entities || msg.entities || [];
}

return [{
  json: {
    media_group_id: msg.media_group_id || null,
    message_id: msg.message_id,
    chat_id: String(msg.chat?.id || ''),
    type,
    Topic,
    file_id,
    caption,
    entities: JSON.stringify(entities),
    date: msg.date,
  }
}];

