function parseDateTimeFlexible(str) {
  let cleanStr = String(str || "").trim();

  cleanStr = cleanStr.replace(/private/gi, "").trim();
  cleanStr = cleanStr.replace(/\s+/g, " ");

  let timePart = "";
  let datePart = "";

  if (cleanStr.includes(" - ")) {
    const parts = cleanStr.split(" - ");
    if (parts.length !== 2) throw new Error("Sai định dạng");
    timePart = parts[0].trim();
    datePart = parts[1].trim();
  } else {
    const match = cleanStr.match(/^(\d{1,2}:\d{2})\s+(\d{1,2}[\/-]\d{1,2}[\/-]\d{4})$/);
    if (!match) throw new Error("Sai định dạng");
    timePart = match[1];
    datePart = match[2];
  }

  const [hour, minute] = timePart.split(":").map(Number);
  const [day, monthRaw, year] = datePart.split(/[\/-]/).map(Number);
  const month = monthRaw - 1;

  if ([hour, minute, day, month, year].some(v => isNaN(v))) {
    throw new Error("Dữ liệu không hợp lệ");
  }

  return new Date(year, month, day, hour, minute);
}

function tinhDuration(partnerTime, bdTime) {
  if (!partnerTime || !bdTime) return "";

  const partnerStr = String(partnerTime).trim();
  const bdStr = String(bdTime).trim();

  if (partnerStr.toLowerCase().includes("private")) {
    return "Private";
  }

  try {
    const datePartner = parseDateTimeFlexible(partnerStr);
    const dateBD = parseDateTimeFlexible(bdStr);

    const diffInMs = datePartner - dateBD;

    if (isNaN(diffInMs)) return "Lỗi định dạng";

    const totalMinutes = diffInMs / (1000 * 60);
    const totalHours = diffInMs / (1000 * 60 * 60);
    const totalDays = diffInMs / (1000 * 60 * 60 * 24);

    if (totalMinutes < 0) return "Sai mốc thời gian";
    if (totalMinutes < 60) return "sau " + Math.round(totalMinutes) + " phút";
    if (totalHours < 24) return "sau " + Math.round(totalHours) + " tiếng";

    const roundedDays = Math.round(totalDays * 2) / 2;
    return "sau " + roundedDays.toFixed(1) + " ngày";
  } catch (e) {
    return "Lỗi định dạng";
  }
}

